  ["tips.creator.shaman"] = "Создать Шамана\n|cffffffffЭта кнопка создаёт бота класса Шаман.|r\n\n|cffff0000Левый клик для выбора пола Шамана.|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.creator.rogue"] = "Создать Разбойника\n|cffffffffЭта кнопка создаёт бота класса Разбойник.|r\n\n|cffff0000Левый клик для выбора пола Разбойника.|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.creator.priest"] = "Создать Жреца\n|cffffffffЭта кнопка создаёт бота класса Жрец.|r\n\n|cffff0000Левый клик для выбора пола Жреца.|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.creator.paladin"] = "Создать Паладина\n|cffffffffЭта кнопка создаёт бота класса Паладин.|r\n\n|cffff0000Левый клик для выбора пола Паладина|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.creator.mage"] = "Создать Мага\n|cffffffffЭта кнопка создаёт бота класса Маг.|r\n\n|cffff0000Левый клик для выбора пола Мага.|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.creator.hunter"] = "Создать Охотника\n|cffffffffЭта кнопка создаёт бота класса Охотник.|r\n\n|cffff0000Левый клик для выбора пола Охотника.|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.creator.druid"] = "Создать Друида\n|cffffffffЭта кнопка создаёт бота класса Друид.|r\n\n|cffff0000Левый клик для выбора пола Друида.|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.creator.deathknight"] = "Создать Рыцаря Смерти\n|cffffffffЭта кнопка создаёт бота класса Рыцарь Смерти.|r\n\n|cffff0000Левый клик для выбора пола Рыцаря Смерти.|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.creator.notarget"] = "У меня нет цели.",
  ["tips.creator.gendermale"] = "Создать мужского спутника.\n|cffffffffСильный, смелый и всегда готов к бою... или к кружке пива.|r\n\n|cffff0000Левый клик для создания|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.creator.genderfemale"] = "Создать женского спутника.\n|cffffffffЭлегантна, смертоносна и её никогда нельзя недооценивать.|r\n\n|cffff0000Левый клик для создания|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.creator.genderrandom"] = "Создать бота со случайным полом.\n|cffffffffСудьба решит за тебя!|r\n\n|cffff0000Левый клик для создания|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.creator.inspect"] = "Осмотреть цель\n|cffffffffЭта кнопка откроет окно осмотра вашей цели.|r\n\n|cffff0000Левый клик - открыть окно осмотра|r\n|cff999999(Порядок выполнения: Цель)|r",
  ["tips.creator.init"] = "Авто-инициализация\n|cffffffffИспользуйте эту кнопку для авто-инициализации цели, рейда или группы.\nЕсть 2 ограничения, так как экипировка будет перезаписана:\n- не работает с персонажами из списка Playerbot\n- не работает с членами гильдии.|r\n\n|cffff0000Левый клик - авто-инициализировать цель|r\n|cff999999(Порядок выполнения: Цель)|r\n\n|cffff0000Правый клик - авто-инициализировать группу|r\n|cff999999(Порядок выполнения: Рейд, Группа)|r",
  ["tips.unit.selfbot"] = "Селфбот\n|cffffffffЭта кнопка включает/выключает режим селфбота.|r\n\n|cffff0000Левый клик - переключить селфбот|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.unit.button"] = "|cffffffff\nЭта кнопка добавляет/удаляет NAME в/из вашей группы.\nMultiBot запросит у Playerbot боевые и небоевые стратегии.\nСтратегии можно настроить с помощью панелей слева и справа.\nПанели появятся после добавления бота.|r\n\n|cffff0000Левый клик - добавить NAME|r\n|cff999999(Порядок выполнения: Система)|r\n\n|cffff0000Правый клик - удалить NAME|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.master"] = "Управление юнитами\n|cffffffffЗдесь отображаются Playerbot'ы.\nКаждая кнопка соответствует одному из ваших персонажей, членов гильдии или друзей.\nПорядок выполнения показывает получателя команд.|r\n\n|cffff0000Левый клик - показать/скрыть юниты|r\n|cff999999(Порядок выполнения: Система)|r\n\n|cffff0000Правый клик - обновить список|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.filter"] = "Фильтр по классу\n|cffffffffФильтр позволяет отображать юнитов по классам.|r\n\n|cffff0000Левый клик - показать/скрыть опции|r\n|cff999999(Порядок выполнения: Система)|r\n\n|cffff0000Правый клик - сбросить фильтр|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.deathknight"] = "Фильтр по классу\n|cffffffffФильтрует юнитов по рыцарям смерти.|r\n\n|cffff0000Левый клик - фильтровать рыцарей смерти|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.druid"] = "Фильтр по классу\n|cffffffffФильтрует юнитов по друидам.|r\n\n|cffff0000Левый клик - фильтровать друидов|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.hunter"] = "Фильтр по классу\n|cffffffffФильтрует юнитов по охотникам.|r\n\n|cffff0000Левый клик - фильтровать охотников|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.mage"] = "Фильтр по классу\n|cffffffffФильтрует юнитов по магам.|r\n\n|cffff0000Левый клик - фильтровать магов|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.paladin"] = "Фильтр по классу\n|cffffffffФильтрует юнитов по паладинам.|r\n\n|cffff0000Левый клик - фильтровать паладинов|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.priest"] = "Фильтр по классу\n|cffffffffФильтрует юнитов по жрецам.|r\n\n|cffff0000Левый клик - фильтровать жрецов|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.rogue"] = "Фильтр по классу\n|cffffffffФильтрует юнитов по разбойникам.|r\n\n|cffff0000Левый клик - фильтровать разбойников|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.shaman"] = "Фильтр по классу\n|cffffffffФильтрует юнитов по шаманам.|r\n\n|cffff0000Левый клик - фильтровать шаманов|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.warlock"] = "Фильтр по классу\n|cffffffffФильтрует юнитов по чернокнижникам.|r\n\n|cffff0000Левый клик - фильтровать чернокнижников|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.warrior"] = "Фильтр по классу\n|cffffffffФильтрует юнитов по воинам.|r\n\n|cffff0000Левый клик - фильтровать воинов|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.none"] = "Фильтр по классу\n|cffffffffСнимает фильтрацию юнитов по классам.|r\n\n|cffff0000Левый клик - снять фильтр|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.roster"] = "Фильтр списков\n|cffffffffФильтр списков позволяет переключаться между разными списками.|r\n\n|cffff0000Левый клик - показать/скрыть опции|r\n|cffff0000Щелкните правой кнопкой мыши, чтобы переключиться на активный состав|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.actives"] = "Фильтр списков\n|cffffffffПоказывает активный список.|r\n\n|cffff0000Левый клик - выбрать активный список|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.players"] = "Фильтр списков\n|cffffffffПоказывает список Playerbot.\nОбычно ваши персонажи и те, кто остался в вашей группе.|r\n\n|cffff0000Левый клик - выбрать список Playerbot|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.members"] = "Фильтр списков\n|cffffffffПоказывает список гильдии.\nСписок гильдии не показывает ваших персонажей.|r\n\n|cffff0000Левый клик - выбрать список гильдии|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.friends"] = "Фильтр списков\n|cffffffffПоказывает список друзей.\nСписок друзей не показывает ваших персонажей и членов гильдии.|r\n\n|cffff0000Левый клик - выбрать список друзей|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.favorites"] = "Фильтр состава\n|cffffffffПоказывать только тех ботов, которых вы отметили как избранных.|r\n\n|cffff0000ЛКМ для активации|r\n|cff999999(Выполняется: Система)|r",
  ["tips.units.pvpstatsmaster"] = "PvP-статистика\n|cffffffffОтправить команду PvP-статистики...|r\n\n|cffff0000ЛКМ, чтобы открыть меню|r\n|cff999999(Выполнено: Система)|r",
  ["tips.units.pvpstatstobot"] = "Отправить боту",
  ["tips.units.pvpstatstoparty"] = "Отправить группе",
  ["tips.units.pvpstatstoraid"] = "Отправить рейду",
  ["tips.units.browse"] = "Просмотр\n|cffffffffЭтой кнопкой можно просматривать списки.\nБудет скрыта, если в списке меньше 11 юнитов.|r\n\n|cffff0000Левый клик - просмотреть список|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.invite"] = "Управление приглашениями\n|cffffffffЭтим элементом можно автоматически заполнять группу.\nЛевая кнопка - для приглашения в группу, правая - для рейда.\nДополнительно, правый клик добавит или удалит всех ботов сразу.\nЕсли вы не в группе - все боты будут добавлены, иначе - удалены.|r\n\n|cffff0000Левый клик - показать/скрыть управление|r\n|cff999999(Порядок выполнения: Система)|r\n\n|cffff0000Правый клик - добавить/удалить всех ботов|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.inviteParty5"] = "Группа из 5\n|cffffffffЭтой кнопкой можно заполнить группу.\nИспользует юнитов из выбранного списка, игнорируя фильтр классов.\nОстанавливается в конце списка или при достижении 5 участников.|r\n\n|cffff0000Левый клик - пригласить участников группы|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.inviteRaid10"] = "Рейд из 10\n|cffffffffЭтой кнопкой можно заполнить рейд.\nИспользует юнитов из выбранного списка, игнорируя фильтр классов.\nОстанавливается в конце списка или при достижении 10 участников.|r\n\n|cffff0000Левый клик - пригласить участников рейда|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.inviteRaid25"] = "Рейд из 25\n|cffffffffЭтой кнопкой можно заполнить рейд.\nИспользует юнитов из выбранного списка, игнорируя фильтр классов.\nОстанавливается в конце списка или при достижении 25 участников.|r\n\n|cffff0000Левый клик - пригласить участников рейда|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.inviteRaid40"] = "Рейд из 40\n|cffffffffЭтой кнопкой можно заполнить рейд.\nИспользует юнитов из выбранного списка, игнорируя фильтр классов.\nОстанавливается в конце списка или при достижении 40 участников.|r\n\n|cffff0000Левый клик - пригласить участников рейда|r\n|cff999999(Порядок выполнения: Система)|r",
  ["tips.units.alliance"] = "Iniciar/Cerrar sesión de todos los PlayerBots\n|cffffffffInicia o cierra la sesión de todos los PlayerBots a los que tengas acceso.\nEsta función puede tardar en llenar las barras de botones de cada PlayerBot,\ndependiendo del número total de PlayerBots.\n\n|cffff0000Clic izquierdo para iniciar sesión en todos los PlayerBots|r\n|cff999999(Ejecutado por: Sistema)|r\n\n|cffff0000Clic derecho para cerrar sesión en todos los PlayerBots|r\n|cff999999(Ejecutado por: Sistema)|r",
